#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
string L,R;
LL X,Y,n,ch,dp[50][2][2][50][50],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    cin>>X>>Y;
    while(X)L=(char)(X%2+'0')+L,X/=2;
    while(Y)R=(char)(Y%2+'0')+R,Y/=2;
    n=R.size(),ch=n-L.size();
    while(L.size()<n)L="0"+L;
    dp[0][0][0][0][0]=1;for(int i=0;i<n;i++)
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)
    for(int p=0;p<=i;p++)for(int q=0;p+q<=i;q++)
    for(int k=(x?0:(L[i]-'0'));k<=(y?1:(R[i]-'0'));k++){
        int nx=(x||k>(L[i]-'0')),ny=(y||k<(R[i]-'0'));
        int np=p+(!k&&(!(!x&&i<=ch))),nq=q+k;
        dp[i+1][nx][ny][np][nq]+=dp[i][x][y][p][q];
    }
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)
        for(int p=0;p<=n;p++)for(int q=0;p+q<=n&&q<=p;q++)
            Ans+=dp[n][x][y][p][q];
    cout<<Ans<<"\n";
    return 0;
}
